      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const taskService = require('./service');

router.post('/:projectId/tasks', (req, res) => {
  const task = taskService.createTask(req.params.projectId, req.body);
  if (!task) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.status(201).json({ task });
});

router.get('/:projectId/tasks', (req, res) => {
  const tasks = taskService.getAllTasks(req.params.projectId);
  if (!tasks) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.json({ tasks });
});

router.get('/:projectId/tasks/:taskId', (req, res) => {
  const task = taskService.getTaskById(req.params.projectId, req.params.taskId);
  if (!task) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ task });
});

router.patch('/:projectId/tasks/:taskId', (req, res) => {
  const task = taskService.updateTask(req.params.projectId, req.params.taskId, req.body);
  if (!task) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ task });
});

module.exports = router;
