  const comment = commentService.createComment(req.params.projectId, req.params.taskId, req.body);
  if (!comment) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.status(201).json({ comment });
});

router.get('/:projectId/tasks/:taskId/comments', (req, res) => {
  const comments = commentService.getAllComments(req.params.projectId, req.params.taskId);
  if (!comments) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ comments });
});

module.exports = router;
